import './App.css';
import Header from "./components/Header"
import Home from "./pages/Home"
import { BrowserRouter, Routes, Route } from "react-router-dom";


function App() {
  return (
    <BrowserRouter>
      <Routes>
        <Route index element={<Home />}>
          <Route path="/" element={<Header />} />
        </Route>        
      </Routes>
    </BrowserRouter>
  );
}

export default App;
